18	#ifndef __INTERNAL_VEC_MAT_MUL_TILING_H__
19	#define __INTERNAL_VEC_MAT_MUL_TILING_H__
20	
21	#include <stdlib.h>
22	
23	#ifdef ENA_DYNAMIC_CALC_CACHE_CONFIG
24	#include "nds_intrinsic.h"
25	#include <math.h>
26	#endif
27	
28	#if defined(ENA_VEC_ISA)
29	#include "internal_vec_isa.h"
30	
31	enum rvv_type{
32	    RVV_ORIGINAL,
33	    RVV_TILING,
34	    RVV_PACKING
35	};
36	
37	static inline void vec_mat_mul_rvv_tiling(const MM_TYPE* src1, const MM_TYPE* src2, MM_TYPE* dst, uint32_t row, uint32_t col, uint32_t col2, uint32_t tiling_size)
38	{
39	    //4*4 by 4*vl
40	    int row_4 = row >> 2;
41	    int max_row = row_4 << 2;
42	
43	    const MM_TYPE* A = src1;
44	    const MM_TYPE* B = src2;
45	    const MM_TYPE* C = dst;
46	    int r, k, kk, cc, vl;
47	    int kk_tiling_size, cc_tiling_size, max_kk_tiling_size;
48	    const MM_TYPE* A11, * B11, \
49	                 * A21, * B21, \
50	                 * A31, * B31, \
51	                 * A41, * B41, \
52	                 * C1, * C2, * C3, * C4;
53	    for (kk = 0; kk < col; kk += tiling_size)
54	    {
55	        kk_tiling_size = ((kk + tiling_size) > col ? col : (kk + tiling_size));
56	        if ((kk + tiling_size) <= col)
57	        {
58	            max_kk_tiling_size = kk_tiling_size - (tiling_size & 3);
59	        }
60	        else
61	        {
62	            max_kk_tiling_size = col - ((col - kk) & 3);
63	        }
64	        for (cc = 0; cc < col2; cc += tiling_size)
65	        {
66	            cc_tiling_size = ((cc + tiling_size) > col2 ? col2 : (cc + tiling_size));
67	            for (r = 0; r < max_row; r += 4)
68	            {
69	                int mulLen = cc_tiling_size - cc;
70	                while (mulLen > 0)
71	                {
72	                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M4);
73	                    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); //sum
74	                    NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0); //sum
75	                    NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0); //sum
76	                    NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0); //sum
77	
78	                    A11 = A + r * col + kk;
79	                    A21 = A11 + col;
80	                    A31 = A21 + col;
81	                    A41 = A31 + col;
82	                    B11 = B + kk * col2 + cc_tiling_size - mulLen;
83	                    B21 = B11 + col2;
84	                    B31 = B21 + col2;
85	                    B41 = B31 + col2;
86	                    C1 = C + r * col2 + cc_tiling_size - mulLen;
87	                    C2 = C1 + col2;
88	                    C3 = C2 + col2;
89	                    C4 = C3 + col2;
90	                    for (k = kk; k < max_kk_tiling_size; k += 4)
91	                    {
92	                        DEF_VLOAD_V(NDS_VEC_V16, B11);
93	                        DEF_VLOAD_V(NDS_VEC_V20, B21);
94	                        DEF_VLOAD_V(NDS_VEC_V24, B31);
95	                        DEF_VLOAD_V(NDS_VEC_V28, B41);
96	                        MM_TYPE tmpa11 = *A11++;
97	                        MM_TYPE tmpa21 = *A21++;
98	                        MM_TYPE tmpa31 = *A31++;
99	                        MM_TYPE tmpa41 = *A41++;
100	                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa11, NDS_VEC_V16);
101	                        NDS_VEC_VFMACC_VF(NDS_VEC_V4, tmpa21, NDS_VEC_V16);
102	                        NDS_VEC_VFMACC_VF(NDS_VEC_V8, tmpa31, NDS_VEC_V16);
103	                        NDS_VEC_VFMACC_VF(NDS_VEC_V12, tmpa41, NDS_VEC_V16);
104	
105	                        MM_TYPE tmpa12 = *A11++;
106	                        MM_TYPE tmpa22 = *A21++;
107	                        MM_TYPE tmpa32 = *A31++;
108	                        MM_TYPE tmpa42 = *A41++;
109	                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa12, NDS_VEC_V20);
110	                        NDS_VEC_VFMACC_VF(NDS_VEC_V4, tmpa22, NDS_VEC_V20);
111	                        NDS_VEC_VFMACC_VF(NDS_VEC_V8, tmpa32, NDS_VEC_V20);
112	                        NDS_VEC_VFMACC_VF(NDS_VEC_V12, tmpa42, NDS_VEC_V20);
113	
114	                        MM_TYPE tmpa13 = *A11++;
115	                        MM_TYPE tmpa23 = *A21++;
116	                        MM_TYPE tmpa33 = *A31++;
117	                        MM_TYPE tmpa43 = *A41++;
118	                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa13, NDS_VEC_V24);
119	                        NDS_VEC_VFMACC_VF(NDS_VEC_V4, tmpa23, NDS_VEC_V24);
120	                        NDS_VEC_VFMACC_VF(NDS_VEC_V8, tmpa33, NDS_VEC_V24);
121	                        NDS_VEC_VFMACC_VF(NDS_VEC_V12, tmpa43, NDS_VEC_V24);
122	
123	                        MM_TYPE tmpa14 = *A11++;
124	                        MM_TYPE tmpa24 = *A21++;
125	                        MM_TYPE tmpa34 = *A31++;
126	                        MM_TYPE tmpa44 = *A41++;
127	                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa14, NDS_VEC_V28);
128	                        NDS_VEC_VFMACC_VF(NDS_VEC_V4, tmpa24, NDS_VEC_V28);
129	                        NDS_VEC_VFMACC_VF(NDS_VEC_V8, tmpa34, NDS_VEC_V28);
130	                        NDS_VEC_VFMACC_VF(NDS_VEC_V12, tmpa44, NDS_VEC_V28);
131	
132	                        B11 += 4 * col2;
133	                        B21 += 4 * col2;
134	                        B31 += 4 * col2;
135	                        B41 += 4 * col2;
136	                    }
137	                    for (; k < kk_tiling_size; k++)
138	                    {
139	                        DEF_VLOAD_V(NDS_VEC_V16, B11);
140	                        MM_TYPE tmpa11 = *A11++;
141	                        MM_TYPE tmpa21 = *A21++;
142	                        MM_TYPE tmpa31 = *A31++;
143	                        MM_TYPE tmpa41 = *A41++;
144	                        NDS_VEC_VFMACC_VF(NDS_VEC_V0, tmpa11, NDS_VEC_V16);
145	                        NDS_VEC_VFMACC_VF(NDS_VEC_V4, tmpa21, NDS_VEC_V16);
146	                        NDS_VEC_VFMACC_VF(NDS_VEC_V8, tmpa31, NDS_VEC_V16);
147	                        NDS_VEC_VFMACC_VF(NDS_VEC_V12, tmpa41, NDS_VEC_V16);
148	
149	                        B11 += col2;
150	                    }
151	                    DEF_VLOAD_V(NDS_VEC_V16, C1);
152	                    DEF_VLOAD_V(NDS_VEC_V20, C2);
153	                    DEF_VLOAD_V(NDS_VEC_V24, C3);
154	                    DEF_VLOAD_V(NDS_VEC_V28, C4);
155	
156	                    NDS_VEC_VFADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V16);
157	                    NDS_VEC_VFADD_VV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V20);
158	                    NDS_VEC_VFADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V24);
159	                    NDS_VEC_VFADD_VV(NDS_VEC_V12, NDS_VEC_V12, NDS_VEC_V28);
160	
161	                    DEF_VSTORE_V(NDS_VEC_V0, C1);
162	                    DEF_VSTORE_V(NDS_VEC_V4, C2);
163	                    DEF_VSTORE_V(NDS_VEC_V8, C3);
164	                    DEF_VSTORE_V(NDS_VEC_V12, C4);
165	                    mulLen -= vl;
166	                }
167	            }
168	            for (; r < row; r++)
169	            {
170	                int mulLen = cc_tiling_size - cc;
171	                while (mulLen > 0)
172	                {
173	                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M4);
174	                    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); //sum
175	                    A11 = A + r * col + kk;
176	                    B11 = B + kk * col2 + cc_tiling_size - mulLen;
177	                    B21 = B11 + col2;
178	                    B31 = B21 + col2;
179	                    B41 = B31 + col2;
180	                    C1 = C + r * col2 + cc_tiling_size - mulLen;
181	                    for (k = kk; k < max_kk_tiling_size; k += 4)
182	                    {
183	                        DEF_VLOAD_V(NDS_VEC_V16, B11);
184	                        DEF_VLOAD_V(NDS_VEC_V20, B21);
185	                        DEF_VLOAD_V(NDS_VEC_V24, B31);
186	                        DEF_VLOAD_V(NDS_VEC_V28, B41);
