1357	static inline void vec_calc_tiling_size_and_cache_config(uint32_t *cache_size_byte, uint32_t *tiling_size)
1358	{
1359	    /* NOTE: */
1360	    /* Simulator cannot verify these code because of the CSRs below. */
1361	
1362	    if(DEV_SMU->SYSTEMCFG & L2C_CTL_MSK) // CPU supports L2C cache
1363	    {
1364	        if ((DEV_L2C->CFG & L2C_SIZE_MSK) >> L2C_SIZE_OFF)
1365	        {
1366	            *cache_size_byte = (unsigned int)(((DEV_L2C->CFG & L2C_SIZE_MSK) >> L2C_SIZE_OFF) * 128) << 10;
1367	        }
1368	    }
1369	    else if((__nds__mfsr(NDS_MDCM_CFG) >> 6) & 7) // if L1 cache exits.
1370	    {
1371	        // calculate cache_size
1372	        unsigned int seth, set, way, line;
1373	        seth = (__nds__mfsr(NDS_MDCM_CFG) >> 24) & 1;
1374	        set = __nds__mfsr(NDS_MDCM_CFG) & 7;
1375	        way = (__nds__mfsr(NDS_MDCM_CFG) >> 3) & 7;
1376	        line = (__nds__mfsr(NDS_MDCM_CFG) >> 6) & 7;
1377	        // calculate set value
1378	        if (seth == 0)
1379	        {
1380	            set = 64 << set;
1381	        }
1382	        else if (seth == 1)
1383	        {
1384	            set = 32 >> set;
1385	        }
1386	        // calculate way value
1387	        way++;
1388	        // calculate line value
1389	        if (line != 0)
1390	        {
1391	            line = 4 << line;
1392	        }
1393	        *cache_size_byte = set * way * line;
1394	    }
1395	    else
1396	    {
1397	        *cache_size_byte = 0;
1398	    }
1399	
1400	    //decide bsize aka. tiling_size
1401	    int a;
1402	    int tiling_size_arr[] = { 1,8,16,32,64,128,256,512,1024 };
1403	    int max_tile_size_in_cache = sqrt(((*cache_size_byte) / 3) / sizeof(MM_TYPE));
1404	    for (a = 1; a < sizeof(tiling_size_arr) / sizeof(tiling_size_arr[0]); a++)
1405	    {
1406	        if (tiling_size_arr[a] > max_tile_size_in_cache)
1407	        {
1408	            *tiling_size = tiling_size_arr[a - 1];
1409	            break;
1410	        }
1411	    }
1412	}
